const QUESTIONS_CCZT_C5 = [
  { id:60901, domain:5, level:3, question:"What is the primary goal of microsegmentation in a Zero Trust network?", options:["Increasing raw network throughput by aggregating links across the core switching fabric across all environments","Reducing the count of firewalls by consolidating them into one large perimeter device","Limiting lateral movement by isolating workloads into small, individually enforced segments","Eliminating the need for any identity verification of users connecting remotely"], correct:2, explanation:"Microsegmentation confines breaches by isolating workloads, restricting lateral movement. It is not about throughput or removing identity checks." },
  { id:60902, domain:5, level:1, question:"Which statement best distinguishes microsegmentation from traditional VLAN segmentation?", options:["VLANs trunk traffic at layer 2 while microsegmentation always tunnels it over IPsec links","VLAN segmentation inspects application-layer payloads that microsegmentation cannot examine across all environments","Microsegmentation requires every host to share one flat broadcast domain to function","Microsegmentation enforces granular per-workload policy independent of physical network topology"], correct:3, explanation:"Microsegmentation applies identity/workload-aware policy decoupled from topology, unlike coarse VLANs. It does not require a flat domain." },
  { id:60903, domain:5, level:2, question:"In Zero Trust, what does continuous authentication primarily address?", options:["Re-evaluating trust throughout a session rather than relying solely on initial login","Verifying user identity once at login and trusting the session indefinitely afterward","Encrypting only the authentication handshake while leaving the rest in cleartext","Storing passwords in a vault so users never have to enter credentials again"], correct:0, explanation:"Continuous authentication re-assesses trust during the session, not just at login. Trusting indefinitely contradicts Zero Trust." },
  { id:60904, domain:5, level:2, question:"Why is FIDO2/WebAuthn considered phishing-resistant compared to OTP-based MFA?", options:["It rotates the shared one-time secret faster than an attacker can relay it onward","It sends a longer numeric code that is harder for a person to read aloud over a call across all environments","It uses origin-bound public-key cryptography so credentials cannot be replayed elsewhere","It encrypts the OTP in transit so the SMS message body cannot be intercepted easily"], correct:2, explanation:"FIDO2 binds credentials to the origin via public-key crypto, defeating relay/phishing. OTPs remain phishable because they can be relayed." },
  { id:60905, domain:5, level:2, question:"What does device posture assessment evaluate before granting access?", options:["The user's job title and department as recorded in the HR system of record","The geographic distance between the user's home office and the data center","The endpoint's security state such as patch level, encryption, and running EDR","The total bandwidth available on the link between the device and the gateway across all environments"], correct:2, explanation:"Posture assessment checks endpoint health (patching, encryption, EDR) as an access signal. Job title and bandwidth are not posture." },
  { id:60906, domain:5, level:1, question:"Just-in-time (JIT) access most directly reduces which risk?", options:["The risk of standing privileges that remain available long after they are needed","The risk of network congestion caused by too many simultaneous privileged sessions","The risk of weak passwords being reused across multiple unrelated applications","The risk of certificates expiring before an automated renewal job can run them"], correct:0, explanation:"JIT grants privileges only when needed and revokes them after, shrinking standing access. It does not address congestion or password reuse." },
  { id:60907, domain:5, level:2, question:"How does just-enough access (least privilege) complement just-in-time access?", options:["It extends each granted session indefinitely so re-requests are never necessary later across all environments","It replaces role assignments entirely with a single global administrator entitlement","It scopes the granted permissions to the minimum required, while JIT limits their duration","It caches credentials locally so the identity provider is not queried on each request"], correct:2, explanation:"Just-enough scopes the breadth of permission; JIT scopes its time window. Together they minimize both scope and duration." },
  { id:60908, domain:5, level:2, question:"What is policy-as-code in a Zero Trust program?", options:["Hand-written firewall rules that operators edit directly on each device console across all environments","A printed policy binder that auditors review once per annual compliance cycle","A spreadsheet of approved IP addresses emailed to the network team each week","Defining and versioning access policies in machine-readable files managed like software"], correct:3, explanation:"Policy-as-code expresses policy in version-controlled, machine-readable form for automation and review. Binders and spreadsheets are manual." },
  { id:60909, domain:5, level:3, question:"Which is a core advantage of RBAC compared with pure ABAC?", options:["It evaluates dozens of contextual attributes in real time for every single request","It removes the need to define any policies because roles are inferred automatically across all environments","It offers simpler administration and clearer auditing when roles map cleanly to duties","It always grants finer-grained, context-aware decisions than attribute-based models"], correct:2, explanation:"RBAC is simpler to administer and audit when roles align to job functions. Fine-grained context is ABAC's strength, not RBAC's." },
  { id:60910, domain:5, level:2, question:"When is ABAC typically preferred over RBAC in Zero Trust?", options:["When the organization wants to stop logging access decisions to reduce storage cost","When there are only a handful of static roles that rarely change over many years","When administrators wish to avoid writing or maintaining any access policy at all","When access must depend on dynamic context like device posture, location, or time"], correct:3, explanation:"ABAC shines when decisions need dynamic attributes (posture, location, time). Few static roles favor RBAC's simplicity." },
  { id:60911, domain:5, level:2, question:"What does mutual TLS (mTLS) provide between two workloads?", options:["One-way server authentication only, leaving the calling client entirely unverified","A faster handshake by skipping certificate validation on both sides of the link","Bidirectional authentication and encryption so both endpoints verify each other","Compression of payloads to lower bandwidth while sending the data unencrypted"], correct:2, explanation:"mTLS authenticates and encrypts both directions, each side validating the other's certificate. One-way auth is plain TLS." },
  { id:60912, domain:5, level:3, question:"Why is encrypting east-west (workload-to-workload) traffic important in Zero Trust?", options:["Because internal traffic is no longer implicitly trusted and may traverse hostile paths","Because perimeter firewalls already inspect all internal traffic and decrypt it again","Because east-west links are always faster and so encryption adds no measurable latency across all environments","Because regulations forbid any plaintext from ever leaving the data center boundary"], correct:0, explanation:"Zero Trust assumes no implicit internal trust, so east-west traffic is encrypted. Perimeter inspection does not cover lateral paths." },
  { id:60913, domain:5, level:3, question:"What is a non-person entity (NPE) identity in Zero Trust operations?", options:["A machine, service, or workload identity used for automated authentication","A guest user account temporarily issued to a visiting third-party contractor","A shared mailbox that several human employees log into with one password","A disabled account retained only for historical audit-trail reference purposes"], correct:0, explanation:"NPE identities represent machines/services/workloads authenticating without a human. Guest and shared human accounts are person-based." },
  { id:60914, domain:5, level:3, question:"What is the main purpose of a SIEM in Zero Trust operations?", options:["Automatically rotating all cryptographic keys used by internal microservices across all environments","Aggregating and correlating logs to detect threats and provide security visibility","Issuing short-lived workload certificates to every container in the cluster","Encrypting database tables at rest using customer-managed master keys"], correct:1, explanation:"A SIEM aggregates and correlates security logs for detection and visibility. Key rotation and cert issuance are other tools' jobs." },
  { id:60915, domain:5, level:3, question:"How does SOAR extend the value of a SIEM in Zero Trust?", options:["By storing raw logs for far longer than the SIEM retention policy allows by default","By replacing the need for any human analyst to review high-severity alerts ever","By encrypting the SIEM's own internal database to protect it from tampering","By automating and orchestrating response playbooks triggered from detected events"], correct:3, explanation:"SOAR automates/orchestrates response playbooks on detections, accelerating containment. It does not eliminate analyst oversight." },
  { id:60916, domain:5, level:2, question:"What does UEBA primarily analyze?", options:["Static firewall rule sets to find unused or overly permissive entries to remove","Baselines of normal user and entity behavior to flag anomalous deviations","Certificate expiration dates across the workload mesh to schedule renewals","Network cabling diagrams to optimize the physical placement of switches"], correct:1, explanation:"UEBA baselines normal behavior and flags anomalies indicating compromise or misuse. It is not a rule cleanup or cabling tool." },
  { id:60917, domain:5, level:1, question:"Which signal would most likely raise a session risk score during a session?", options:["The user opening a help-desk ticket through the approved internal portal","Impossible travel where logins occur from distant locations within minutes","A scheduled antivirus scan completing successfully on the managed endpoint","The user changing their display name in the corporate directory profile"], correct:1, explanation:"Impossible travel is a classic anomaly raising risk and possible step-up. Routine tickets, scans, and profile edits are benign." },
  { id:60918, domain:5, level:3, question:"What is the purpose of step-up authentication?", options:["Lowering authentication requirements after a user has been active for an hour across all environments","Logging the user out automatically every five minutes regardless of activity","Requiring stronger verification when a request is higher-risk or more sensitive","Disabling MFA once a device has successfully authenticated three times"], correct:2, explanation:"Step-up adds stronger verification for higher-risk or sensitive actions. The other options weaken rather than strengthen assurance." },
  { id:60919, domain:5, level:2, question:"ZTNA most directly improves on traditional VPN by:", options:["Providing per-application access based on identity and context rather than network reach","Granting broad network-layer access to the subnet once the tunnel is established across all environments","Requiring users to install heavier always-on agents than any VPN client needs","Routing all traffic through a single data-center concentrator for inspection"], correct:0, explanation:"ZTNA gives least-privilege per-application access by identity/context, unlike VPNs that expose the network. Broad subnet access is the VPN model." },
  { id:60920, domain:5, level:1, question:"What does CWPP stand for and protect in Zero Trust?", options:["Central Web Proxy Protocol, routing all employee browsing through one gateway","Continuous Wireless Provisioning Process, onboarding new access points to the LAN across all environments","Cloud Workload Protection Platform, securing servers, VMs, and container workloads","Cloud Wide Password Policy, enforcing complexity rules on every cloud login"], correct:2, explanation:"CWPP secures workloads (servers, VMs, containers) across environments. The other expansions are invented distractors." },
  { id:60921, domain:5, level:1, question:"Microsegmentation policies are best expressed in terms of which attribute?", options:["The physical switch port number to which a server happens to be cabled today","The DHCP lease duration assigned to the host on its current subnet segment","The serial number printed on the chassis of the underlying hardware appliance","Workload identity and labels so policy follows the workload regardless of IP"], correct:3, explanation:"Identity/label-based policy follows workloads independent of IP or port. Cabling and serials are not policy attributes." },
  { id:60922, domain:5, level:2, question:"Adaptive re-authentication is triggered most appropriately by:", options:["A fixed timer that forces every user to re-login exactly on the hour, every hour","A meaningful change in risk context such as new device, network, or location","The completion of any routine read-only query against a low-sensitivity dataset","The user scrolling through several pages of an internal documentation wiki site"], correct:1, explanation:"Adaptive re-auth responds to risk-context changes, not arbitrary timers or benign reads. Risk drives the prompt." },
  { id:60923, domain:5, level:3, question:"Centralizing authentication through an enterprise identity provider helps Zero Trust by:", options:["Removing the requirement for any multi-factor authentication on sensitive apps across all environments","Providing a single authoritative point to enforce policy, MFA, and conditional access","Letting each application keep its own separate local password database in sync","Storing all user passwords in cleartext so the help desk can recover them fast"], correct:1, explanation:"A central IdP enforces consistent MFA, policy, and conditional access. Local password stores and cleartext contradict ZT." },
  { id:60924, domain:5, level:3, question:"An endpoint failing posture checks should typically be:", options:["Granted full access immediately so the user is never inconvenienced at work across all environments","Permanently banned from the network with no path to regain access at all","Ignored because posture is only advisory and never affects access decisions","Quarantined or given limited access until it remediates to a compliant state"], correct:3, explanation:"Non-compliant devices get limited/quarantined access pending remediation. Full access or permanent bans are inappropriate extremes." },
  { id:60925, domain:5, level:2, question:"Privileged access management in Zero Trust emphasizes:", options:["Permanent administrator rights so engineers never have to request elevation again","Brokered, time-bound, audited elevation with session monitoring and recording","Sharing one root credential among the whole operations team for convenience","Disabling logging on privileged sessions to reduce the volume of stored data"], correct:1, explanation:"ZT PAM brokers time-bound, audited, monitored elevation. Permanent rights, shared roots, and disabled logging are anti-patterns." },
  { id:60926, domain:5, level:2, question:"A key benefit of managing access policy as code is:", options:["It enables version control, peer review, testing, and automated deployment of policy","It guarantees that no policy will ever need to be reviewed by a human again","It forces every policy change to be applied manually on each enforcement point","It hides policy logic from auditors so the rule set stays confidential from them across all environments"], correct:0, explanation:"Policy-as-code brings VCS, review, testing, and CI/CD to policy. It improves rather than hides auditability." },
  { id:60927, domain:5, level:2, question:"A secrets management system in Zero Trust should:", options:["Embed long-lived credentials directly in application source code repositories across all environments","Email new credentials to developers whenever a service needs to authenticate","Print static API keys to application logs so operators can find them quickly","Issue short-lived, dynamically generated secrets and rotate them automatically"], correct:3, explanation:"Secrets managers issue short-lived, rotated, dynamic secrets. Hardcoding, emailing, or logging secrets are insecure practices." },
  { id:60928, domain:5, level:2, question:"A conditional access policy decides access based on:", options:["Only whether the username and password entered happen to match the directory across all environments","Exclusively the time of day, ignoring who the user or device actually is","The order in which applications were registered in the catalog historically","Combined signals like user, device compliance, location, app, and real-time risk"], correct:3, explanation:"Conditional access combines multiple signals (user, device, location, risk). Password-only or single-signal checks are weaker." },
  { id:60929, domain:5, level:2, question:"Access recertification (attestation) campaigns are used to:", options:["Provision brand-new accounts in bulk for an incoming class of employees","Permanently disable multi-factor authentication for long-tenured employees across all environments","Periodically review and confirm whether existing access is still appropriate","Generate marketing reports about overall application adoption across teams"], correct:2, explanation:"Recertification reviews existing entitlements to remove unneeded access. It is not provisioning or MFA disablement." },
  { id:60930, domain:5, level:3, question:"Privilege creep is best described as:", options:["A sudden spike in network latency when too many privileged sessions overlap","The gradual accumulation of access rights that are no longer needed over time","The automatic expiration of credentials at the end of each work shift cycle","The encryption of administrator traffic as it crosses untrusted network paths"], correct:1, explanation:"Privilege creep is unneeded rights accumulating as roles change. The other options describe unrelated phenomena." },
  { id:60931, domain:5, level:3, question:"Timely deprovisioning in Zero Trust primarily prevents:", options:["Excess license costs from idle seats sitting unused in the subscription plan","Slow login performance caused by an oversized enterprise directory tree","Duplicate display names appearing in the corporate global address list","Orphaned accounts retaining access after a user leaves or changes roles"], correct:3, explanation:"Deprovisioning removes access when users leave/change roles, preventing orphaned accounts. License cost is a secondary concern." },
  { id:60932, domain:5, level:2, question:"A Zero Trust approach to Kubernetes typically includes:", options:["Allowing all pods to communicate freely so services can discover each other","Default-deny network policies plus workload identity and mTLS between services","Running every workload as cluster-admin to avoid permission troubleshooting","Disabling the API server audit log to reduce the cluster's storage footprint across all environments"], correct:1, explanation:"ZT in k8s uses default-deny NetworkPolicies, workload identity, and mTLS. Open pod comms and cluster-admin defaults are insecure." },
  { id:60933, domain:5, level:2, question:"API security in Zero Trust relies heavily on:", options:["Trusting any request that originates from inside the corporate network range across all environments","A single shared API key embedded in the mobile app's distributed binary file","Strong authentication, fine-grained authorization, and validation on every call","Rate limiting alone as the complete defense against unauthorized API misuse"], correct:2, explanation:"ZT APIs require per-call authN, fine-grained authZ, and input validation. Network trust and shared keys are insufficient." },
  { id:60934, domain:5, level:2, question:"Data-centric security with DLP in Zero Trust focuses on:", options:["Blocking all outbound internet traffic regardless of its content or context across all environments","Encrypting only the network perimeter while data at rest stays in plaintext","Counting the total number of files stored on each managed endpoint daily","Classifying data and controlling its movement based on sensitivity and policy"], correct:3, explanation:"DLP classifies data and governs its movement by sensitivity. Blanket blocking and perimeter-only encryption miss the data focus." },
  { id:60935, domain:5, level:3, question:"How does SASE/SSE relate to Zero Trust operations?", options:["It replaces Zero Trust principles with a purely perimeter-based security model","It is an on-premises-only appliance that cannot enforce policy for remote users","It applies exclusively to email filtering and has no bearing on network access","It delivers ZTNA, SWG, CASB, and FWaaS as converged cloud-delivered services"], correct:3, explanation:"SASE/SSE converges ZTNA, SWG, CASB, FWaaS in the cloud, operationalizing ZT for distributed users. It is not perimeter-only." },
  { id:60936, domain:5, level:1, question:"Integrating Zero Trust with DevSecOps means:", options:["Embedding identity, policy, and security testing into automated CI/CD pipelines","Performing all security checks manually only after the application ships to users","Granting the build server unrestricted standing access to every production system","Disabling pipeline gates so deployments are never blocked by security findings"], correct:0, explanation:"ZT+DevSecOps embeds identity, policy, and testing into CI/CD. Manual-only checks and standing build access undermine it." },
  { id:60937, domain:5, level:1, question:"After a Zero Trust rollout, alert tuning is important because:", options:["New telemetry can flood the SOC with false positives that must be refined down","Zero Trust eliminates the need to monitor any logs once policies are enforced","Tuning permanently disables detections to keep the alert queue empty for analysts","Alerts should always be left at default thresholds to preserve vendor support"], correct:0, explanation:"ZT adds telemetry that can cause false positives needing tuning. ZT does not remove monitoring, and disabling detections is wrong." },
  { id:60938, domain:5, level:2, question:"A common pitfall when deploying ZTNA is:", options:["Mapping application entitlements too granularly so users can reach only their apps","Requiring multi-factor authentication on the most sensitive internal applications","Logging connection events to the SIEM for later correlation and investigation","Over-broad access policies that recreate VPN-style implicit trust by accident"], correct:3, explanation:"Overly broad ZTNA policies reintroduce VPN-like implicit trust. Granular entitlements, MFA, and logging are good practices." },
  { id:60939, domain:5, level:1, question:"Measuring Zero Trust maturity in operations typically tracks:", options:["Only the total dollar amount spent on security products in the fiscal year across all environments","Progress across pillars like identity, device, network, and automation over time","The number of physical badge readers installed at the building entrances","How many marketing webinars the security team attended during the quarter"], correct:1, explanation:"ZT maturity tracks pillar progress (identity, device, network, automation). Spend and badge counts are not maturity measures." },
  { id:60940, domain:5, level:1, question:"Cloud workload protection in Zero Trust includes:", options:["Granting every workload a permanent broad IAM role to avoid permission errors","Leaving security groups fully open so autoscaling instances always reach peers across all environments","Relying solely on the cloud provider's default settings with no added controls","Workload identity, least-privilege IAM, runtime protection, and config hardening"], correct:3, explanation:"CWP combines workload identity, least-privilege IAM, runtime protection, and hardening. Broad roles and open groups are insecure." },
  { id:60941, domain:5, level:1, question:"Which control most directly limits lateral movement after an endpoint is compromised?", options:["Single sign-on across all enterprise applications for user convenience","Microsegmentation that isolates workloads and denies unneeded east-west flows","A faster corporate internet circuit with more available bandwidth headroom across all environments","A longer mandatory password length applied to every standard user account"], correct:1, explanation:"Microsegmentation contains compromise by denying lateral flows. SSO, bandwidth, and password length do not stop lateral movement." },
  { id:60942, domain:5, level:3, question:"Which best describes a software-defined perimeter (SDP) in Zero Trust?", options:["A static DMZ subnet where all externally facing servers are permanently placed","A hardware load balancer that distributes traffic across redundant data centers","A legacy modem pool used to provide dial-up backup connectivity for branches","An identity-driven overlay that hides resources until a device is authenticated"], correct:3, explanation:"SDP cloaks resources until identity/device are verified, granting least-privilege connections. A DMZ subnet is the old perimeter model." },
  { id:60943, domain:5, level:3, question:"What is the role of a policy enforcement point (PEP) in a Zero Trust architecture?", options:["It enforces the access decision by allowing or blocking the actual connection","It decides the final access policy by evaluating all collected risk signals","It stores the long-term audit logs for compliance reporting and investigations","It generates the cryptographic keys used for all workload-to-workload sessions"], correct:0, explanation:"The PEP enforces (allows/blocks) connections per the decision. Making the decision is the policy decision point's role." },
  { id:60944, domain:5, level:1, question:"What is the role of a policy decision point (PDP) in Zero Trust?", options:["It evaluates signals and policy to produce the access decision for each request","It physically blocks or permits packets at the network interface in real time across all environments","It terminates TLS sessions and re-encrypts traffic for downstream inspection","It provisions new user accounts automatically from the HR system of record"], correct:0, explanation:"The PDP evaluates policy and signals to decide; the PEP enforces. The PDP does not itself move packets." },
  { id:60945, domain:5, level:1, question:"Which practice best supports continuous diagnostics and mitigation (CDM)?", options:["Continuously inventorying assets, configurations, and vulnerabilities for action","Scanning assets once during the annual audit and archiving the report afterward across all environments","Disabling vulnerability scanners to avoid generating noise on the network links","Relying only on user-submitted tickets to learn about misconfigured systems"], correct:0, explanation:"CDM continuously inventories assets/configs/vulns to drive mitigation. Annual-only scans and disabled scanners defeat the purpose." },
  { id:60946, domain:5, level:2, question:"In Zero Trust, why are short-lived certificates preferred for workloads?", options:["They are cheaper to purchase than long-lived certificates from a public CA","They never need to be rotated because they are valid for only a single request across all environments","They limit the window of misuse if a key is compromised and reduce revocation reliance","They allow workloads to skip mutual authentication during the TLS handshake"], correct:2, explanation:"Short-lived certs shrink the compromise window and reduce CRL/OCSP reliance via frequent rotation. They still require mTLS." },
  { id:60947, domain:5, level:2, question:"What is a service mesh commonly used for in Zero Trust microservices?", options:["Compiling application source code into deployable container images automatically","Provisioning physical servers in the data center using bare-metal automation","Enforcing mTLS, identity, and fine-grained authorization between microservices","Generating end-user marketing dashboards from aggregated application metrics"], correct:2, explanation:"A service mesh enforces mTLS, workload identity, and authZ between services. It does not compile code or provision bare metal." },
  { id:60948, domain:5, level:1, question:"Which is the most appropriate response when a session's risk score rises mid-session?", options:["Immediately delete the user account to prevent any further potential misuse","Ignore the change because risk scores are only meaningful at initial login time across all environments","Trigger step-up authentication or restrict actions until trust is re-established","Permanently disable the application for all users until the next review cycle"], correct:2, explanation:"Rising risk should trigger step-up or restriction, re-establishing trust. Deleting accounts or ignoring risk are inappropriate." },
  { id:60949, domain:5, level:1, question:"What does least privilege mean in operational terms?", options:["Every user receives administrator rights to minimize help-desk escalation volume","Subjects receive only the minimum access required to perform their function","Access is granted broadly first and then narrowed only after an incident occurs","All access decisions are delegated to end users to choose their own permissions"], correct:1, explanation:"Least privilege grants only the minimum needed. Broad-then-narrow and user self-grant contradict the principle." },
  { id:60950, domain:5, level:3, question:"Which is a benefit of integrating identity context into network policy?", options:["Policies can ignore who the user is and rely purely on source IP addresses","Network teams can stop maintaining any access policies once identity is added","Access can follow the user and device identity rather than network location","All traffic becomes exempt from inspection once the user authenticates once"], correct:2, explanation:"Identity-aware policy lets access follow user/device rather than location. IP-only policy is the legacy model ZT moves away from." },
  { id:60951, domain:5, level:2, question:"What is a key operational risk of overly aggressive Zero Trust policies?", options:["Excessive trust granted to unmanaged devices accessing sensitive resources","Reduced logging that prevents the SOC from investigating security incidents across all environments","Automatic disabling of multi-factor authentication for privileged accounts","Legitimate business workflows being blocked, harming productivity and adoption"], correct:3, explanation:"Too-aggressive policies block legitimate work, hurting adoption. The other options describe weakened security, not over-restriction." },
  { id:60952, domain:5, level:1, question:"Which telemetry source is most valuable for detecting compromised credentials?", options:["Static network diagrams describing the intended topology of each data center","Quarterly access recertification spreadsheets exported from the IGA system","Authentication logs combined with behavioral analytics on login patterns","Physical badge-in records from the building's door access control system"], correct:2, explanation:"Auth logs plus behavioral analytics reveal credential misuse (e.g., anomalous logins). Diagrams and badge records are weak signals here." },
  { id:60953, domain:5, level:3, question:"How does Zero Trust treat traffic originating from inside the corporate LAN?", options:["It is automatically trusted because it never crosses the network perimeter","It is treated as untrusted and subject to verification like any other traffic","It is exempt from encryption requirements because it stays within the building","It is logged but never evaluated against access policy to reduce overhead"], correct:1, explanation:"ZT never grants implicit trust to internal traffic; it is verified like external. Implicit LAN trust is exactly what ZT rejects." },
  { id:60954, domain:5, level:3, question:"What is the primary purpose of session recording for privileged access?", options:["To provide an auditable record of privileged actions for accountability and review","To reduce the bandwidth consumed by administrative remote sessions over WAN","To replace the need for multi-factor authentication on administrator accounts","To automatically grant standing access so admins avoid repeated elevation requests"], correct:0, explanation:"Session recording gives accountability and forensic review of privileged actions. It does not replace MFA or grant standing access." },
  { id:60955, domain:5, level:2, question:"Which is the best approach to machine identity at scale?", options:["Sharing one static service account across many microservices for simplicity","Embedding a single API token in a configuration file deployed everywhere","Issuing unique, attestable, automatically rotated identities per workload","Reusing human user accounts for automated jobs to reuse existing entitlements"], correct:2, explanation:"Unique, attestable, auto-rotated workload identities are best practice. Shared accounts, static tokens, and human-account reuse are risky." },
  { id:60956, domain:5, level:1, question:"What does behavioral analytics add beyond signature-based detection?", options:["A guaranteed elimination of all false positives in the alerting pipeline","A complete replacement for endpoint detection and response agents entirely","Detection of novel or insider threats that no predefined signature matches","The ability to block traffic without generating any log entries at all"], correct:2, explanation:"Behavioral analytics catch novel/insider activity lacking signatures. It complements, not replaces, EDR and does not guarantee zero FPs." },
  { id:60957, domain:5, level:1, question:"Which is an example of a strong, phishing-resistant authenticator?", options:["A six-digit one-time code delivered to the user by SMS text message","A static memorized PIN reused across several different internal applications","A hardware security key implementing FIDO2/WebAuthn with origin binding","A security question whose answer is the user's mother's maiden name"], correct:2, explanation:"FIDO2 hardware keys with origin binding resist phishing. SMS OTPs, static PINs, and security questions are phishable or weak." },
  { id:60958, domain:5, level:2, question:"Why should access reviews be risk-prioritized rather than uniform?", options:["Because reviewing every entitlement equally guarantees the fastest possible cycle","Because focusing effort on high-risk access yields more value than uniform reviews","Because low-risk access should be reviewed far more frequently than high-risk access","Because risk has no bearing on how often entitlements ought to be recertified"], correct:1, explanation:"Risk-prioritized reviews concentrate effort where it matters most. Treating all access identically wastes effort on low-risk items." },
  { id:60959, domain:5, level:1, question:"What is the operational value of policy automation in Zero Trust?", options:["It removes the requirement to ever test policies before deploying them widely","It permanently locks policies so that no future changes can be introduced at all","It enables consistent, fast, and auditable policy changes with less human error","It hides all policy decisions from the SIEM so logs remain smaller in size"], correct:2, explanation:"Policy automation gives consistent, fast, auditable changes with fewer errors. It does not skip testing or hide decisions." },
  { id:60960, domain:5, level:2, question:"Which describes secure remote access in a Zero Trust model?", options:["A full-tunnel VPN that places the remote device directly on the internal subnet across all environments","An open RDP port forwarded through the firewall to each internal workstation","Per-application access brokered by identity and device posture without network exposure","A shared jump host that all contractors log into with the same credentials"], correct:2, explanation:"ZT remote access brokers per-app connections by identity/posture, avoiding network exposure. Full VPNs and open RDP are legacy risks." },
  { id:60961, domain:5, level:2, question:"What is a primary reason to encrypt data in transit between microservices?", options:["To compress payloads so that inter-service calls consume less total bandwidth","To eliminate the need for any authentication between the communicating services","To allow intermediate proxies to cache responses for faster repeat retrieval","To prevent interception and tampering on internal paths assumed to be hostile"], correct:3, explanation:"Encrypting in transit prevents interception/tampering on assumed-hostile internal paths. It does not remove the need for authN." },
  { id:60962, domain:5, level:2, question:"Which metric best indicates progress reducing standing privilege?", options:["The total number of user accounts that exist within the enterprise directory across all environments","The average length of passwords enforced across all standard user accounts","The number of help-desk tickets opened about forgotten passwords each week","The proportion of privileged access granted just-in-time versus standing rights"], correct:3, explanation:"The JIT-vs-standing ratio shows reduction of standing privilege. Account counts and password length do not measure this." },
  { id:60963, domain:5, level:1, question:"What is conditional access most aligned with in Zero Trust?", options:["Continuously evaluating signals to allow, block, or step up each access attempt","Granting access once and never re-evaluating the decision during the session across all environments","Allowing access strictly by source IP range without considering identity","Disabling access entirely whenever any single risk signal is observed at all"], correct:0, explanation:"Conditional access continuously evaluates signals to permit/block/step-up. One-time grants and IP-only checks are weaker." },
  { id:60964, domain:5, level:3, question:"Which is a sound practice for secrets in CI/CD pipelines?", options:["Injecting short-lived secrets from a vault at runtime and never persisting them","Committing API keys to the repository so all developers can run the build","Printing credentials to build logs so failures are easier to troubleshoot fast across all environments","Reusing one production database password across every pipeline environment"], correct:0, explanation:"Vault-injected, short-lived, non-persisted secrets are best practice. Committing, logging, or reusing secrets are insecure." },
  { id:60965, domain:5, level:1, question:"What does default-deny mean in a Zero Trust network policy?", options:["All traffic is permitted unless an explicit rule blocks that specific flow across all environments","All traffic is blocked unless an explicit policy expressly allows that flow","Traffic is permitted during business hours and blocked outside those hours","Traffic is allowed only if it originates from a registered internal subnet"], correct:1, explanation:"Default-deny blocks everything except explicitly allowed flows. Default-allow and time/subnet-only rules are not default-deny." },
  { id:60966, domain:5, level:1, question:"How should orphaned service accounts be handled operationally?", options:["Discovered, attributed to an owner, and disabled or removed if unjustified","Left active indefinitely in case a future application happens to need them","Granted broader privileges so they can serve more applications efficiently","Exempted from logging because automated accounts rarely cause real incidents"], correct:0, explanation:"Orphaned service accounts should be found, owned, and removed if unneeded. Leaving them active or broadening them increases risk." },
  { id:60967, domain:5, level:2, question:"What is the main benefit of integrating ZTNA logs with a SIEM?", options:["It enables correlation of access events with other telemetry for detection","It reduces the storage cost of logs by discarding most connection events","It removes the need for the ZTNA service to authenticate users at connect time","It automatically tunes all detection rules without any analyst involvement"], correct:0, explanation:"Feeding ZTNA logs to the SIEM enables cross-source correlation and detection. It does not discard events or remove authN." },
  { id:60968, domain:5, level:1, question:"Which is a hallmark of a mature Zero Trust monitoring capability?", options:["Comprehensive visibility with real-time analytics across identity, device, and network","Collecting logs but never analyzing them until after a breach is disclosed","Monitoring only the perimeter firewall while ignoring internal east-west flows across all environments","Relying on monthly manual log reviews as the sole detection mechanism used"], correct:0, explanation:"Mature monitoring spans identity/device/network with real-time analytics. Perimeter-only or after-the-fact review is immature." },
  { id:60969, domain:5, level:3, question:"Why is automated deprovisioning preferred over manual offboarding?", options:["It increases the time accounts remain active after an employee departs entirely","It eliminates the need to maintain any record of who had access historically","It removes access promptly and consistently, reducing orphaned-account windows","It requires the departing employee to approve removal of their own access"], correct:2, explanation:"Automated deprovisioning removes access promptly/consistently. Manual processes leave longer orphan windows and gaps." },
  { id:60970, domain:5, level:2, question:"What is the purpose of a trust algorithm in Zero Trust?", options:["To physically route encrypted packets across the lowest-latency network path across all environments","To generate symmetric keys for bulk encryption of stored database records","To compute an access decision from inputs like identity, device, and behavior","To schedule periodic backups of the policy engine's configuration database"], correct:2, explanation:"The trust algorithm computes access decisions from multiple inputs. It is not a routing, key-gen, or backup function." },
  { id:60971, domain:5, level:2, question:"Which scenario best justifies step-up authentication?", options:["A user viewing the company holiday calendar from a managed corporate laptop","A user reading an internal newsletter on the intranet during business hours","A user initiating a large financial transfer from an unfamiliar new device","A user updating their preferred notification settings within a self-service app"], correct:2, explanation:"A high-value action from an unfamiliar device warrants step-up. Low-risk reads and benign setting changes do not." },
  { id:60972, domain:5, level:2, question:"What does workload identity attestation verify?", options:["The geographic region where the workload's container image was first built","The number of replicas currently running for a given microservice deployment","That a workload is genuinely what it claims before issuing it an identity","The total CPU and memory resources allocated to the workload by the scheduler"], correct:2, explanation:"Attestation verifies a workload's authenticity before identity issuance. Replica counts and resource sizing are unrelated." },
  { id:60973, domain:5, level:2, question:"Which is a correct statement about RBAC role explosion?", options:["It occurs when too few roles force everyone into one overly broad permission set","It occurs when many narrow roles proliferate and become hard to manage and audit","It refers to roles automatically expiring at the end of each calendar quarter","It describes the process of merging all roles into a single administrative role"], correct:1, explanation:"Role explosion is proliferation of narrow roles, hurting manageability. The other options misstate the phenomenon." },
  { id:60974, domain:5, level:2, question:"What is a recommended way to reduce east-west attack surface in cloud VPCs?", options:["Place all instances in one open security group so they can reach each other","Disable flow logs to avoid generating large volumes of network telemetry data","Assign public IP addresses to every instance for simpler direct connectivity","Apply least-privilege security groups and segment by workload and sensitivity"], correct:3, explanation:"Least-privilege security groups and segmentation cut east-west surface. Open groups, disabled logs, and public IPs increase risk." },
  { id:60975, domain:5, level:2, question:"What does continuous monitoring enable that periodic auditing does not?", options:["Near-real-time detection of policy violations and anomalous activity as it occurs","A one-time snapshot of compliance captured at the end of each fiscal year","A reduced need to collect any telemetry from endpoints or network devices","Automatic remediation of all findings without any defined response process across all environments"], correct:0, explanation:"Continuous monitoring detects issues in near-real-time, unlike periodic snapshots. It does not remove telemetry needs or auto-fix all." },
  { id:60976, domain:5, level:2, question:"Which is the most appropriate use of UEBA output?", options:["Prioritizing investigation of high-confidence anomalies and feeding risk scoring","Automatically terminating any account that deviates even slightly from baseline across all environments","Replacing the SIEM entirely so that no log correlation is performed any longer","Disabling endpoint agents whenever user behavior appears completely normal"], correct:0, explanation:"UEBA anomalies should prioritize investigation and inform risk scoring. Auto-terminating on minor deviations causes harm." },
  { id:60977, domain:5, level:1, question:"What is the relationship between identity and Zero Trust?", options:["Identity is irrelevant once a device is connected to the trusted internal network","Identity matters only for external users and not for internal employees at all","Identity is replaced entirely by network location as the basis for access","Identity is a foundational pillar that drives most access decisions in the model"], correct:3, explanation:"Identity is foundational and drives access decisions. ZT explicitly moves away from network location as the trust basis." },
  { id:60978, domain:5, level:2, question:"What is a key consideration when replacing a legacy VPN with ZTNA?", options:["Maintaining the same broad network access so users notice no change at all across all environments","Disabling all logging so the new solution generates less data to store","Mapping applications and entitlements to enforce least-privilege per-app access","Removing multi-factor authentication to simplify the user login experience"], correct:2, explanation:"ZTNA migration requires mapping apps/entitlements for least-privilege access. Preserving broad access defeats the purpose." },
  { id:60979, domain:5, level:2, question:"Which best describes microsegmentation enforcement at the host level?", options:["A perimeter firewall inspecting all traffic entering the data center building","A core router applying ACLs that only filter traffic between data centers","Host-based agents or kernel hooks enforcing per-workload policy on each node","A DNS server resolving internal names to addresses for service discovery"], correct:2, explanation:"Host-level microsegmentation uses agents/kernel hooks per workload. Perimeter firewalls and core routers are coarse-grained." },
  { id:60980, domain:5, level:1, question:"What is the goal of integrating posture signals into access decisions?", options:["To grant access faster by skipping verification for known internal devices","To deny or limit access from devices that fail to meet security requirements","To collect device inventory data purely for asset-management reporting only across all environments","To replace user authentication with device authentication in all cases"], correct:1, explanation:"Posture signals gate access for non-compliant devices. They augment, not replace, user authentication." },
  { id:60981, domain:5, level:1, question:"Which practice helps prevent alert fatigue after a Zero Trust deployment?", options:["Tuning detections, deduplicating, and prioritizing alerts by risk and context","Routing every raw log event directly to analysts without any prior correlation","Disabling all medium-severity alerts permanently to shrink the alert queue","Increasing thresholds so high that genuine attacks never trigger an alert"], correct:0, explanation:"Tuning, dedup, and risk-based prioritization reduce fatigue. Dumping raw events or muting real threats are harmful extremes." },
  { id:60982, domain:5, level:1, question:"What does encrypting traffic with mTLS additionally provide beyond confidentiality?", options:["Guaranteed lower latency on every network hop between communicating services","Mutual authentication of both endpoints, establishing workload-level trust","Automatic load balancing of requests across all available service replicas","Compression of repeated headers to reduce overall bandwidth consumption"], correct:1, explanation:"mTLS adds mutual endpoint authentication on top of confidentiality. It does not provide latency guarantees or load balancing." },
  { id:60983, domain:5, level:1, question:"Which is a sound approach to privileged access for break-glass scenarios?", options:["A permanently enabled shared root login kept handy for any emergency at all","Disabling all monitoring during emergencies so responders can move faster","Granting every responder standing administrator rights to avoid delays later across all environments","Tightly controlled, heavily audited emergency accounts used only when necessary"], correct:3, explanation:"Break-glass accounts must be tightly controlled and heavily audited. Permanent shared roots and disabled monitoring are dangerous." },
  { id:60984, domain:5, level:3, question:"What is a primary purpose of behavioral session risk scoring?", options:["To assign a fixed risk value to each user that never changes after onboarding","To dynamically adjust trust during a session based on observed activity","To replace authentication entirely with a single numeric trust threshold","To rank applications by popularity for capacity-planning purposes only"], correct:1, explanation:"Session risk scoring dynamically adjusts trust from observed behavior. Fixed values and replacing authN are incorrect." },
  { id:60985, domain:5, level:1, question:"Which is a benefit of policy-as-code for compliance auditing?", options:["Auditors must manually inspect each enforcement device's local configuration","Policy changes become invisible to auditors to protect proprietary logic","Policy history is captured in version control, providing a clear audit trail","Compliance evidence is generated only once at the start of each program"], correct:2, explanation:"Version-controlled policy gives a clear, reviewable audit trail. It improves rather than hides auditability." },
  { id:60986, domain:5, level:2, question:"Which describes a correct east-west segmentation strategy for sensitive data stores?", options:["Restrict database access to only the specific services that legitimately need it","Allow any application server to query the database to simplify connectivity","Expose the database on a public subnet so remote analysts can connect directly across all environments","Share one database credential among all services to reduce credential sprawl"], correct:0, explanation:"Restricting DB access to only required services enforces least privilege. Broad or public access and shared creds increase risk." },
  { id:60987, domain:5, level:3, question:"What is the purpose of continuous device compliance checks?", options:["To verify posture only at enrollment and trust the device forever afterward","To re-evaluate device health over time and adjust access if it degrades","To measure device performance for capacity planning across the fleet","To inventory installed software solely for software-license reconciliation"], correct:1, explanation:"Continuous compliance re-checks device health and adjusts access on degradation. Enroll-once trust contradicts ZT." },
  { id:60988, domain:5, level:1, question:"How does Zero Trust change the assumption about network breach?", options:["It assumes breaches are impossible once the perimeter firewall is properly tuned","It assumes only external attackers pose a threat and ignores insider risk","It assumes breach is inevitable and designs controls to contain and limit impact","It assumes encrypted traffic can never be the vector for any compromise"], correct:2, explanation:"ZT assumes breach and limits blast radius. Perimeter-only confidence and ignoring insiders are pre-ZT assumptions." },
  { id:60989, domain:5, level:3, question:"Which is an effective control against credential stuffing in a Zero Trust IdP?", options:["Risk-based authentication with MFA, rate limiting, and anomaly detection","Allowing unlimited login attempts so legitimate users are never locked out","Storing passwords with a fast unsalted hash to speed up login verification","Disabling account lockout to reduce help-desk password-reset call volume"], correct:0, explanation:"Risk-based auth, MFA, rate limiting, and anomaly detection counter stuffing. Unlimited attempts and weak hashing increase exposure." },
  { id:60990, domain:5, level:1, question:"What is the operational role of an identity governance (IGA) tool in Zero Trust?", options:["Managing the lifecycle of identities, entitlements, and access certifications","Encrypting all east-west traffic between workloads within the data center","Terminating TLS connections and inspecting payloads at the network edge","Generating cryptographic keys for the workload certificate authority service across all environments"], correct:0, explanation:"IGA manages identity/entitlement lifecycle and certifications. Encryption and TLS termination are other components' roles." },
  { id:60991, domain:5, level:2, question:"Why integrate DLP signals into Zero Trust access decisions?", options:["To block all file downloads regardless of the data's actual classification across all environments","To replace identity verification with content scanning as the sole control","To count files per user for storage-quota enforcement across the estate","To factor data sensitivity into whether and how access or movement is allowed"], correct:3, explanation:"DLP brings data sensitivity into access/movement decisions. Blanket blocking and replacing identity are incorrect." },
  { id:60992, domain:5, level:1, question:"Which is true about SASE in distributed Zero Trust operations?", options:["It forces all remote users back through a single on-premises data center","It applies only to wired LAN connections inside corporate office buildings","It delivers security and networking from the cloud edge close to users","It removes the need to enforce any access policy for cloud applications"], correct:2, explanation:"SASE delivers cloud-edge security/networking near users. Backhauling to one DC is the legacy pattern SASE avoids." },
  { id:60993, domain:5, level:2, question:"What is a recommended way to handle third-party/contractor access in Zero Trust?", options:["Issue them permanent employee accounts so onboarding is faster for managers across all environments","Place them on the internal VPN with the same broad access as full employees","Share an existing team service account so no new identity needs creation","Grant time-bound, least-privilege, and closely monitored access to scoped resources"], correct:3, explanation:"Contractors should get time-bound, least-privilege, monitored access. Permanent or broad access and shared accounts are risky." },
  { id:60994, domain:5, level:2, question:"What does an enforcement-point bypass typically indicate?", options:["A correctly functioning Zero Trust control that is operating exactly as designed","A planned maintenance window that the change-management board approved earlier","A normal optimization that reduces latency for high-priority business traffic","A gap where traffic reaches resources without passing through policy enforcement"], correct:3, explanation:"A bypass means traffic evades enforcement, a serious gap. It is not a designed or benign optimization." },
  { id:60995, domain:5, level:2, question:"Which best describes the operational handling of policy exceptions in Zero Trust?", options:["Granting permanent exceptions whenever a team requests one to avoid friction across all environments","Hiding exceptions from audit so the policy set appears uniformly clean","Documenting, time-limiting, and periodically reviewing every exception granted","Applying exceptions broadly to all similar systems to save review effort"], correct:2, explanation:"Exceptions should be documented, time-limited, and reviewed. Permanent, hidden, or broad exceptions undermine the program." },
  { id:60996, domain:5, level:1, question:"How does runtime protection contribute to container Zero Trust?", options:["By scanning images only once in the registry and never observing running pods","By granting containers broad host privileges to simplify their operation","By detecting and blocking anomalous behavior in workloads as they execute","By disabling network policies so containers can reach all cluster services"], correct:2, explanation:"Runtime protection watches executing workloads for anomalies. Registry-only scanning and broad privileges leave runtime gaps." },
  { id:60997, domain:5, level:2, question:"What is a primary aim of integrating SOAR playbooks with identity systems?", options:["To increase the number of manual steps required to contain a compromised account across all environments","To permanently delete all logs associated with any investigated user account","To automatically disable or restrict accounts when high-confidence threats appear","To replace the identity provider with the SOAR platform for authentication"], correct:2, explanation:"SOAR-identity integration auto-restricts compromised accounts, speeding containment. It does not delete logs or replace the IdP." },
  { id:60998, domain:5, level:3, question:"Which is a sound metric for Zero Trust operational effectiveness?", options:["The number of new firewalls purchased during the most recent budget cycle","Mean time to detect and contain anomalous access across monitored systems","The total count of employees who attended the annual security awareness day","The number of marketing blog posts published about the Zero Trust journey"], correct:1, explanation:"MTTD/MTTC for anomalous access measures operational effectiveness. Purchases and attendance are not effectiveness metrics." },
  { id:60999, domain:5, level:2, question:"What does a Zero Trust policy engine consume to make decisions?", options:["Only the static source IP address of the requesting device on the network","Solely the time of day at which the access request happens to be made","Multiple signals including identity, device posture, context, and threat intel","Exclusively the application's published popularity ranking among end users across all environments"], correct:2, explanation:"The policy engine fuses many signals (identity, posture, context, intel). Single-factor inputs like IP alone are insufficient." },
  { id:61000, domain:5, level:2, question:"Why are service accounts often a Zero Trust blind spot?", options:["They frequently have broad, long-lived credentials with little monitoring or rotation","They authenticate using stronger phishing-resistant factors than human users","They are always disabled by default and require explicit enablement to function across all environments","They cannot be assigned any entitlements within modern identity platforms"], correct:0, explanation:"Service accounts often hold broad, static, unmonitored credentials, a major blind spot. They typically lack strong factors and rotation." },
  { id:61001, domain:5, level:2, question:"What is the benefit of binding workload identity to short-lived tokens?", options:["It limits exposure if a token leaks because it expires quickly and rotates","It permits the workload to retain the same token across its entire lifetime","It removes the need for the workload to authenticate to any peer service","It allows the token to be shared safely among many unrelated workloads"], correct:0, explanation:"Short-lived tokens limit leak exposure via quick expiry/rotation. They are not meant to be long-lived or shared." },
  { id:61002, domain:5, level:2, question:"Which is a correct operational practice for conditional access policy changes?", options:["Deploying changes directly to all users in production without any testing first","Applying the broadest possible policy first and narrowing only after complaints","Testing in report-only or pilot mode before enforcing broadly to limit disruption","Avoiding documentation so that the policy logic remains flexible and undisclosed across all environments"], correct:2, explanation:"Pilot/report-only testing before broad enforcement limits disruption. Untested broad rollouts and missing docs are risky." },
  { id:61003, domain:5, level:2, question:"What does the term blast radius refer to in Zero Trust?", options:["The maximum geographic distance over which a wireless access point can reach across all environments","The total bandwidth a denial-of-service attack can consume on the uplink","The number of users who can log in concurrently to one application server","The extent of damage or access an attacker can reach from a single compromise"], correct:3, explanation:"Blast radius is the reachable impact from one compromise, which segmentation/least-privilege shrink. The others are unrelated." },
  { id:61004, domain:5, level:2, question:"Which is the best way to operationalize least privilege for cloud IAM?", options:["Attaching wildcard administrator policies to every role to avoid access errors","Sharing one powerful role across all teams to reduce the number of policies","Disabling IAM logging so that permission analysis does not slow operations","Granting narrowly scoped permissions and refining them using access analyzers"], correct:3, explanation:"Narrow scopes refined by access analyzers operationalize least privilege. Wildcards, shared roles, and disabled logs are anti-patterns." },
  { id:61005, domain:5, level:3, question:"What is a key reason to monitor non-person entity authentication closely?", options:["NPEs never fail authentication and so their logs contain no useful signal","Compromised machine identities can enable stealthy lateral movement and persistence","NPE traffic is always encrypted, making any monitoring of it entirely redundant across all environments","Machine accounts cannot be granted access to sensitive systems by design"], correct:1, explanation:"Compromised NPEs enable stealthy lateral movement, so they need monitoring. They can fail authN and do hold real entitlements." },
  { id:61006, domain:5, level:3, question:"What is the role of attribute sources (PIPs) in an ABAC decision?", options:["They enforce the final allow-or-deny verdict directly on the network link across all environments","They supply attributes such as posture, role, and risk to the policy engine","They store the long-term archive of access logs for compliance reporting","They issue the workload certificates used in mutual TLS between services"], correct:1, explanation:"Policy information points feed attributes to the engine. Enforcement, log archiving, and cert issuance are different functions." },
  { id:61007, domain:5, level:1, question:"Which is a common operational pitfall in early Zero Trust adoption?", options:["Investing too heavily in visibility before enforcing any restrictive policies","Attempting to boil the ocean instead of phasing rollout by priority and risk","Mapping data flows and dependencies thoroughly before changing any controls","Engaging stakeholders early to align Zero Trust with business priorities first"], correct:1, explanation:"Trying to do everything at once is a classic pitfall; phased, risk-based rollout works better. The other options are good practices." },
  { id:61008, domain:5, level:2, question:"What is the purpose of just-in-time elevation for administrators?", options:["To grant permanent administrator rights so elevation is never needed again","To provide temporary elevated rights only for the duration of a specific task","To share a single administrator credential among the operations team members across all environments","To bypass approval workflows so urgent changes can be applied without delay"], correct:1, explanation:"JIT elevation grants temporary rights for a task, then revokes them. Permanent rights, shared creds, and bypassed approvals are unsafe." },
  { id:61009, domain:5, level:1, question:"How does Zero Trust treat managed versus unmanaged devices?", options:["Both receive identical full access once the user authenticates successfully across all environments","Unmanaged devices are always granted broader access for guest convenience","Managed devices are blocked while only unmanaged devices may connect freely","Unmanaged devices typically receive more limited access based on lower trust"], correct:3, explanation:"Unmanaged devices, having lower trust, get more limited access. Identical or broader unmanaged access contradicts ZT." },
  { id:61010, domain:5, level:3, question:"Which is the most effective way to detect privilege creep operationally?", options:["Periodic access reviews comparing granted entitlements against actual usage","Waiting for an incident to reveal which accounts had excessive permissions across all environments","Granting all access permanently so reviews are no longer needed at all","Counting only the number of accounts rather than their actual entitlements"], correct:0, explanation:"Reviews comparing entitlements to usage surface creep. Waiting for incidents or counting accounts alone are insufficient." },
  { id:61011, domain:5, level:2, question:"What does encrypting data at rest contribute to a data-centric Zero Trust model?", options:["It protects data confidentiality if storage media or backups are compromised","It guarantees that no authorized user can ever read the protected data again","It removes the requirement to authorize access to the underlying data store","It replaces the need for network encryption between communicating services"], correct:0, explanation:"At-rest encryption protects data if media/backups are stolen. It complements, not replaces, authorization and in-transit encryption." },
  { id:61012, domain:5, level:2, question:"Which describes effective integration of Zero Trust with a CI/CD pipeline?", options:["Using short-lived, scoped credentials and policy gates with security scanning","Granting the pipeline broad standing credentials to deploy to any environment","Disabling all automated tests so deployments are never blocked by findings","Allowing any developer to push directly to production without review steps"], correct:0, explanation:"Scoped short-lived creds plus policy gates and scanning embed ZT in CI/CD. Standing creds and skipped gates are insecure." },
  { id:61013, domain:5, level:2, question:"What is a primary purpose of visibility and analytics in Zero Trust?", options:["To inform policy and detect threats through comprehensive activity insight","To reduce the amount of telemetry collected from endpoints and the network","To replace access policies entirely with passive observation of all traffic","To archive logs for legal hold without ever analyzing their contents"], correct:0, explanation:"Visibility/analytics inform policy and drive detection. They do not reduce telemetry or replace enforcement." },
  { id:61014, domain:5, level:1, question:"Which is the best response to repeated failed step-up challenges from one session?", options:["Automatically grant access since the user clearly intends to reach the resource","Treat it as suspicious, restrict the session, and alert for investigation","Disable step-up authentication for that user to remove the friction entirely","Lower the risk threshold so future challenges succeed more easily next time"], correct:1, explanation:"Repeated step-up failures are suspicious and warrant restriction and alerting. Granting access or weakening controls is wrong." },
  { id:61015, domain:5, level:2, question:"What does the principle assume true never trust always verify imply operationally?", options:["Verification happens once and is then trusted for the rest of the session","Only requests from outside the perimeter require any verification at all","Verification can be skipped for devices that previously passed posture checks","Every access request is authenticated and authorized regardless of origin"], correct:3, explanation:"Never-trust-always-verify means every request is authN/authZ'd regardless of origin. One-time or location-based trust violates it." },
  { id:61016, domain:5, level:1, question:"Which is a strong control for API authorization in Zero Trust?", options:["Trusting the calling service purely because it resides in the same VPC subnet across all environments","Accepting any request bearing a shared static key distributed to all clients","Relying on network ACLs alone without verifying the caller's identity claims","Validating scoped tokens and enforcing least-privilege checks on each endpoint"], correct:3, explanation:"Scoped-token validation and per-endpoint least privilege secure APIs. Network/subnet trust and shared static keys are insufficient." },
  { id:61017, domain:5, level:2, question:"What is a key operational benefit of automating access provisioning?", options:["It enforces consistent, policy-driven entitlements and reduces manual errors","It permanently grants access so no future provisioning requests are needed","It removes the requirement to ever deprovision access when roles change","It hides entitlement assignments from auditors to keep records confidential across all environments"], correct:0, explanation:"Automated provisioning enforces consistent, policy-driven entitlements with fewer errors. It does not remove deprovisioning or hide records." },
  { id:61018, domain:5, level:1, question:"How should Zero Trust handle legacy applications that cannot do modern authentication?", options:["Expose them directly to the internal network with no additional controls added","Front them with a proxy or broker that enforces identity, posture, and policy","Grant all users permanent access since the app cannot evaluate any context","Disable logging for them because legacy apps rarely generate useful events"], correct:1, explanation:"A proxy/broker can enforce ZT controls in front of legacy apps. Direct exposure and permanent access leave them unprotected." },
  { id:61019, domain:5, level:3, question:"What does endpoint compliance most directly influence in a ZT decision?", options:["The cost of the device as recorded in the IT asset management system","Whether and how much access the device is permitted given its security state","The brand and model of hardware the employee selected during onboarding","The warranty expiration date tracked by the procurement department's records"], correct:1, explanation:"Compliance/posture gates how much access a device gets. Cost, brand, and warranty are not security signals." },
  { id:61020, domain:5, level:2, question:"Which is a sound approach to scaling microsegmentation policy management?", options:["Hand-editing rules on each host whenever a new workload is deployed anywhere across all environments","Disabling segmentation in busy environments to avoid management overhead","Creating one giant allow-all rule and adding narrow deny rules over time","Using labels/tags and policy-as-code so policy follows workloads automatically"], correct:3, explanation:"Label/tag-driven policy-as-code scales segmentation as workloads change. Manual edits and allow-all defaults do not scale safely." },
  { id:61021, domain:5, level:2, question:"What does session re-authentication protect against?", options:["The risk of users forgetting their passwords during very long work sessions across all environments","The performance impact of maintaining encrypted connections for many hours","Hijacked or stale sessions continuing to access resources without re-verification","The cost of issuing new certificates to workloads at frequent intervals"], correct:2, explanation:"Re-authentication defends against hijacked/stale sessions by re-verifying. The other options are unrelated concerns." },
  { id:61022, domain:5, level:2, question:"Which integration most improves automated containment of compromised endpoints?", options:["Linking the asset inventory to the procurement and budgeting systems only","Forwarding marketing analytics to the SIEM for combined business reporting","Synchronizing the corporate directory with the building badge-access system","Connecting EDR detections to SOAR and network controls to isolate the host"], correct:3, explanation:"EDR-to-SOAR-to-network integration enables automated host isolation. The other integrations do not drive containment." },
  { id:61023, domain:5, level:1, question:"What is the value of tagging workloads with metadata in Zero Trust?", options:["It increases raw network throughput between tagged and untagged workloads","It replaces the need to authenticate any traffic between tagged workloads","It enables identity- and attribute-based policy that follows the workload","It reduces the storage needed to retain logs for the tagged workloads"], correct:2, explanation:"Workload tags drive attribute-based policy that follows the workload. Tags do not boost throughput or replace authentication." },
  { id:61024, domain:5, level:1, question:"Which is a recommended practice for handling dormant privileged accounts?", options:["Keeping them enabled indefinitely in case an administrator needs them later","Granting them additional privileges so they remain useful when reactivated","Excluding them from access reviews because they are not currently in use","Detecting inactivity and disabling or removing them after a defined period"], correct:3, explanation:"Dormant privileged accounts should be detected and disabled/removed. Keeping or broadening them and skipping reviews are risky." },
  { id:61025, domain:5, level:2, question:"What is a defining characteristic of adaptive access control?", options:["Access dynamically tightens or relaxes as real-time risk signals change","Access decisions are fixed at provisioning and never change afterward","Access depends solely on a static list of approved source IP addresses across all environments","Access is granted by majority vote among the user's team members"], correct:0, explanation:"Adaptive access changes dynamically with real-time risk. Fixed, IP-only, or vote-based access are not adaptive." },
  { id:61026, domain:5, level:3, question:"Why should Zero Trust logging capture both allow and deny decisions?", options:["Because complete decision visibility supports detection, forensics, and tuning","Because storing only denials makes the logs smaller and cheaper to retain","Because allow decisions are the only events that ever indicate a real attack across all environments","Because regulators forbid recording any denied access attempts in audit logs"], correct:0, explanation:"Logging both allows/denies gives full visibility for detection, forensics, and tuning. Capturing only one side leaves blind spots." },
  { id:61027, domain:5, level:2, question:"What does a Zero Trust gateway typically do for an application?", options:["It terminates and brokers connections, enforcing identity and policy per request","It permanently caches the application's data to speed up future requests across all environments","It compiles the application's code before delivering it to the end user","It assigns static public IP addresses to each backend application server"], correct:0, explanation:"A ZT gateway brokers connections and enforces identity/policy per request. It is not a compiler or IP-assignment service." },
  { id:61028, domain:5, level:2, question:"Which best supports rapid revocation of access in Zero Trust?", options:["Long-lived sessions and tokens that remain valid for many days at a time","Centralized policy with short-lived tokens so revocation takes effect quickly","Distributing static credentials widely so they can be reused conveniently across all environments","Relying on users to voluntarily stop using access they no longer require"], correct:1, explanation:"Central policy plus short-lived tokens make revocation fast. Long-lived sessions and static creds delay or prevent revocation." },
  { id:61029, domain:5, level:2, question:"What is the purpose of correlating identity, device, and network telemetry?", options:["To reduce the total number of log sources the SOC has to maintain over time","To build a complete picture of activity for accurate detection and decisions","To allow each telemetry source to be analyzed in isolation from the others","To archive raw events without performing any cross-source correlation at all"], correct:1, explanation:"Cross-source correlation builds a full activity picture for better detection. Isolated analysis and pure archiving miss connections." },
  { id:61030, domain:5, level:2, question:"Which is an appropriate way to apply Zero Trust to a database tier?", options:["Use scoped service identities, least-privilege grants, and encrypted connections","Allow all application tiers to connect using one shared database superuser","Expose the database to the internet so remote tools can administer it directly across all environments","Disable query logging on the database to improve transactional performance"], correct:0, explanation:"Scoped identities, least-privilege grants, and encryption secure the DB tier. Shared superusers and internet exposure are unsafe." },
  { id:61031, domain:5, level:3, question:"What does the term policy drift describe in Zero Trust operations?", options:["The deliberate scheduled rotation of cryptographic keys across all workloads","The natural decline in network latency as more capacity is added over time","The migration of user accounts from one identity provider to another one","The gradual divergence between intended policy and what is actually enforced"], correct:3, explanation:"Policy drift is divergence between intended and enforced policy, detectable via policy-as-code. The other options are unrelated." },
  { id:61032, domain:5, level:2, question:"Which is the best reason to use phishing-resistant MFA for privileged accounts?", options:["Privileged accounts log in less often, so stronger factors cause little friction across all environments","Privileged accounts are exempt from monitoring and so need no other controls","Standard MFA is sufficient because attackers rarely target administrator logins","Their compromise yields high impact, so they warrant the strongest authentication"], correct:3, explanation:"High-impact privileged accounts deserve the strongest, phishing-resistant MFA. Low login frequency is not the core rationale." },
  { id:61033, domain:5, level:3, question:"What does a Zero Trust approach to remote work primarily replace?", options:["The corporate identity provider used to authenticate employees and partners across all environments","The endpoint detection and response agents installed on managed laptops","Implicit network trust granted by VPNs with explicit per-resource verification","The data-loss-prevention controls that classify and protect sensitive data"], correct:2, explanation:"ZT remote work replaces VPN implicit trust with explicit per-resource verification. It does not replace IdP, EDR, or DLP." },
  { id:61034, domain:5, level:1, question:"Which is a sound way to reduce false positives from a new ZT detection rule?", options:["Immediately deploy the rule in blocking mode to catch every possible threat","Delete the rule entirely the first time it produces any false positive alert","Raise its severity to critical so analysts always treat its alerts as real","Run it in observation mode, baseline normal activity, then tune thresholds"], correct:3, explanation:"Observation-mode baselining then tuning reduces false positives safely. Blind blocking, deletion, and inflating severity are poor choices." },
  { id:61035, domain:5, level:3, question:"What is the function of an identity broker in federated Zero Trust access?", options:["It stores all application data centrally so federation is no longer needed across all environments","It encrypts east-west traffic between workloads inside the data center","It generates the short-lived certificates used in mutual TLS handshakes","It mediates trust and translates identities between providers and applications"], correct:3, explanation:"An identity broker mediates federated trust and translates identities. It is not a data store, encryptor, or CA." },
  { id:61036, domain:5, level:2, question:"Which describes the right handling of access for a user changing roles?", options:["Add the new role's access and keep all the previous role's access as well","Suspend the user entirely until a full manual re-onboarding is completed","Grant the new role's access and remove entitlements no longer required","Keep the old access permanently so the user can cover both roles forever"], correct:2, explanation:"Role changes should add needed access and remove the old, preventing creep. Stacking or keeping old access causes creep." },
  { id:61037, domain:5, level:1, question:"What is a key purpose of asset inventory in Zero Trust?", options:["To know what must be protected so policy can cover all resources and devices","To calculate the depreciation schedule of hardware for finance reporting","To rank devices by purchase price for the annual procurement planning cycle across all environments","To advertise available services to anonymous users on the public internet"], correct:0, explanation:"You cannot protect what you cannot see; inventory ensures policy covers all assets. Depreciation and pricing are not ZT purposes." },
  { id:61038, domain:5, level:2, question:"Which is a recommended practice for monitoring lateral movement attempts?", options:["Logging only north-south perimeter traffic and ignoring internal connections","Disabling internal flow logs to reduce the data the SIEM has to ingest","Trusting all internal connections so they never trigger any alerts at all","Analyzing east-west flows and authentication patterns for anomalous pivoting"], correct:3, explanation:"Monitoring east-west flows and auth patterns detects lateral pivoting. Perimeter-only logging and trusting internal traffic miss it." },
  { id:61039, domain:5, level:3, question:"What does the term explicit verification mean in Zero Trust?", options:["Assuming verification once a device joins the trusted internal network segment","Verifying identity and context for every request using all available signals","Verifying only the first request in a session and trusting the rest implicitly","Delegating all verification decisions to the end user's own discretion"], correct:1, explanation:"Explicit verification authenticates/authorizes each request using available signals. Implicit or one-time trust is the opposite." },
  { id:61040, domain:5, level:3, question:"Which is the strongest control to protect secrets used by automated workloads?", options:["Embedding the secret as an environment variable baked into the container image","Storing the secret in a shared configuration file readable by all services","Retrieving secrets at runtime from a vault using the workload's own identity","Hardcoding the secret in source so deployments are simple and repeatable"], correct:2, explanation:"Runtime retrieval from a vault via workload identity is strongest. Baking into images, shared files, or hardcoding exposes secrets." },
  { id:61041, domain:5, level:1, question:"What is the purpose of network flow logging in Zero Trust visibility?", options:["To record connections for detecting anomalies and validating segmentation","To compress traffic so that more sessions fit on the same network uplink","To replace the policy engine by deciding access from observed flows alone","To assign quality-of-service priorities to latency-sensitive applications"], correct:0, explanation:"Flow logs reveal connections for anomaly detection and segmentation validation. They do not compress traffic or set access policy." },
  { id:61042, domain:5, level:3, question:"Which is a correct statement about Zero Trust and encryption key management?", options:["Encryption keys should be shared widely so any service can decrypt any data across all environments","Once data is encrypted, the keys no longer need any access controls applied","Keys can safely be stored alongside the ciphertext to simplify operations","Keys should be tightly scoped, rotated, and access-controlled like any secret"], correct:3, explanation:"Keys must be scoped, rotated, and access-controlled. Sharing widely or storing with ciphertext defeats the protection." },
  { id:61043, domain:5, level:1, question:"What does the device pillar of Zero Trust primarily concern?", options:["The physical color and form factor of the hardware issued to employees","Establishing and continuously assessing the trustworthiness of endpoints","The total number of devices purchased during the current fiscal quarter","The brand of operating system preferred by the executive leadership team"], correct:1, explanation:"The device pillar establishes and continuously assesses endpoint trust. Form factor, counts, and OS brand are not the focus." },
  { id:61044, domain:5, level:3, question:"Which is an effective way to enforce least privilege for Kubernetes service accounts?", options:["Scoping RBAC roles narrowly and avoiding default-token automounting where unneeded","Binding every service account to the cluster-admin role for convenience across all environments","Sharing one service account token across all pods in the entire cluster","Disabling RBAC entirely so authorization never blocks any pod request"], correct:0, explanation:"Narrow RBAC and limiting token automount enforce least privilege. Cluster-admin defaults, shared tokens, and disabling RBAC are unsafe." },
  { id:61045, domain:5, level:1, question:"What is the operational goal of integrating threat intelligence into ZT decisions?", options:["To incorporate known-bad indicators and context into access and detection","To increase the latency of access decisions for more thorough review","To replace identity verification with reputation lookups for every request","To archive intelligence feeds without applying them to any live decisions"], correct:0, explanation:"Threat intel enriches access/detection with known-bad context. It does not replace identity checks or sit unused." },
  { id:61046, domain:5, level:2, question:"Which is the best practice for handling shared administrative credentials?", options:["Continue using them but rotate the password once per year for hygiene","Distribute them to more team members so coverage improves during outages","Eliminate them in favor of individual identities with brokered elevation","Store them in a spreadsheet that the on-call engineer can access quickly"], correct:2, explanation:"Shared admin credentials should be eliminated for individual identities with brokered elevation. Annual rotation and wider sharing are weak." },
  { id:61047, domain:5, level:2, question:"What does microperimeter mean in Zero Trust architecture?", options:["A single large boundary encircling the entire corporate data center campus across all environments","A fine-grained boundary placed close around an individual protected resource","The wireless coverage area provided by one ceiling-mounted access point","The maximum number of concurrent sessions one gateway can terminate"], correct:1, explanation:"A microperimeter is a tight boundary around an individual resource. A campus-wide boundary is the legacy macroperimeter." },
  { id:61048, domain:5, level:1, question:"Which is a recommended approach to onboarding a new application into ZTNA?", options:["Publish it with broad access first and tighten only if problems are reported","Define its identity, entitlements, and policy before granting any access","Skip posture checks for the application to accelerate its time to launch","Allow anonymous access initially so usage patterns can be measured freely"], correct:1, explanation:"Defining identity, entitlements, and policy before access enforces least privilege. Broad-first or anonymous access is risky." },
  { id:61049, domain:5, level:3, question:"What is a primary purpose of recertification campaigns in Zero Trust?", options:["To create new entitlements in bulk for an upcoming organizational change","To confirm that existing access remains justified and revoke what is not","To migrate the identity store from one cloud vendor to a different one","To reset every user's password simultaneously on a fixed annual schedule"], correct:1, explanation:"Recertification confirms ongoing justification and revokes unneeded access. It is not bulk provisioning or password reset." },
  { id:61050, domain:5, level:2, question:"Which is the most appropriate use of automation in incident response under ZT?", options:["Automating only the writing of the post-incident report after closure","Automating containment actions like token revocation and host isolation quickly","Automating the permanent deletion of all evidence to keep systems clean","Automating the silencing of all alerts during an active incident investigation across all environments"], correct:1, explanation:"Automating containment (revocation, isolation) speeds response. Deleting evidence and silencing alerts harm investigations." },
  { id:61051, domain:5, level:1, question:"What does the data pillar of Zero Trust emphasize?", options:["Maximizing the raw volume of data stored to improve analytics accuracy","Classifying, protecting, and controlling access to data based on sensitivity","Deleting all historical data after thirty days to minimize storage costs","Replicating every dataset to all regions so any user can reach it quickly across all environments"], correct:1, explanation:"The data pillar classifies and protects data by sensitivity and controls access. Volume, blanket deletion, and replication are not its focus." },
  { id:61052, domain:5, level:2, question:"Which is a sound practice when introducing default-deny segmentation?", options:["Switch all segments to deny at once across the entire production estate","Skip flow discovery and rely on user complaints to find needed connections across all environments","Apply deny only to test environments and never to production workloads","Discover flows first, then progressively enforce deny while monitoring impact"], correct:3, explanation:"Discover flows, then progressively enforce deny with monitoring. Big-bang deny and complaint-driven discovery cause outages." },
  { id:61053, domain:5, level:3, question:"What does continuous authorization mean in Zero Trust?", options:["Re-evaluating whether access should continue as context and risk change","Authorizing a user once and never revisiting the decision during the session","Authorizing access based solely on the network segment the user sits in","Delegating authorization decisions to the application rather than a policy engine"], correct:0, explanation:"Continuous authorization re-evaluates access as context/risk change. One-time or segment-based authorization is the opposite." },
  { id:61054, domain:5, level:2, question:"Which is the best way to handle excessive permissions discovered in an access review?", options:["Remove or right-size the unneeded permissions to restore least privilege","Document them as accepted risk and take no further remediation action","Grant matching permissions to peers so the access appears more consistent","Defer all changes until the next annual review to avoid disrupting users"], correct:0, explanation:"Excessive permissions should be removed/right-sized to restore least privilege. Accepting, spreading, or deferring them sustains risk." },
  { id:61055, domain:5, level:1, question:"What is the relationship between Zero Trust and the principle of microsegmentation?", options:["Microsegmentation is unrelated to Zero Trust and applies only to storage","Microsegmentation operationalizes least privilege at the network layer","Microsegmentation replaces the need for any identity-based access control","Microsegmentation is only relevant for the public-facing perimeter network"], correct:1, explanation:"Microsegmentation enforces least privilege at the network layer, a core ZT technique. It complements, not replaces, identity controls." },
  { id:61056, domain:5, level:1, question:"Which is an effective control to limit token theft impact in Zero Trust?", options:["Issuing tokens with very long lifetimes so users rarely need to re-authenticate","Binding tokens to device and using short lifetimes with continuous evaluation","Allowing tokens to be replayed from any IP to maximize user convenience","Storing tokens in shared locations so multiple services can reuse them"], correct:1, explanation:"Device-bound, short-lived tokens with continuous evaluation limit theft impact. Long lifetimes, replay, and sharing increase it." },
  { id:61057, domain:5, level:2, question:"What is a key operational outcome of strong workload identity?", options:["Workloads can authenticate to each other without relying on network position","Workloads no longer need any authorization checks once identity is established","Workloads automatically gain administrator rights on the hosts they run on","Workloads can share a single identity to simplify certificate management"], correct:0, explanation:"Strong workload identity lets services authenticate by identity, not network position. AuthZ is still required and identities are unique." },
  { id:61058, domain:5, level:2, question:"Which best describes the operational handling of high-risk sign-ins?", options:["Automatically allow them and review the logs at the end of the month","Permanently disable the account on the first high-risk sign-in detected across all environments","Challenge with step-up, restrict, or block based on the assessed risk level","Ignore them because risk scoring is informational and not actionable"], correct:2, explanation:"High-risk sign-ins should trigger step-up, restriction, or block per risk. Allow-and-review and ignoring them are inadequate." },
  { id:61059, domain:5, level:2, question:"What does the network pillar of Zero Trust emphasize?", options:["Maximizing flat connectivity so any device can reach any service instantly","Segmenting and encrypting traffic with policy enforced per connection","Eliminating all internal routing in favor of a single backbone switch","Trusting all traffic that stays within the corporate address space"], correct:1, explanation:"The network pillar emphasizes segmentation, encryption, and per-connection policy. Flat connectivity and internal trust are pre-ZT." },
  { id:61060, domain:5, level:1, question:"Which is a recommended way to measure ZT identity-pillar maturity?", options:["Counting the number of usernames stored in the corporate directory tree","Tracking MFA coverage, phishing-resistance adoption, and risk-based policy use","Measuring the average length of passwords across all standard user accounts across all environments","Recording how many users log in during the busiest hour of each day"], correct:1, explanation:"MFA coverage, phishing-resistance, and risk-based policy gauge identity maturity. Raw counts and password length do not." },
  { id:61061, domain:5, level:1, question:"What is the purpose of just-enough-administration (JEA) style constraints?", options:["Restricting administrative capability to only the specific commands needed","Granting administrators unrestricted shells on every managed server by default","Removing all logging from administrative sessions to reduce stored data","Sharing one constrained endpoint among all administrators simultaneously"], correct:0, explanation:"JEA limits admins to only the commands they need, enforcing least privilege. Unrestricted shells and removed logging are unsafe." },
  { id:61062, domain:5, level:1, question:"Which is the best approach to validating that segmentation policy works as intended?", options:["Assume the policy is correct because it deployed without configuration errors across all environments","Wait for an incident to reveal whether any unintended paths remained open","Validate once at deployment and never re-check as the environment changes","Continuously test and monitor flows to confirm only intended paths are allowed"], correct:3, explanation:"Continuous testing/monitoring confirms only intended flows are allowed. Assuming correctness and one-time checks miss drift." },
  { id:61063, domain:5, level:1, question:"What does the term policy enforcement gap describe?", options:["A scheduled window during which all enforcement is intentionally suspended","The latency introduced when a policy engine evaluates many signals at once","The difference in cost between two competing policy-engine product vendors","A path by which traffic can reach a resource without policy being applied"], correct:3, explanation:"An enforcement gap is a path bypassing policy, a security weakness. It is not a maintenance window or latency measure." },
  { id:61064, domain:5, level:2, question:"Which is a sound operational practice for ZTNA connector placement?", options:["Place a single connector in one region and backhaul all global traffic to it","Disable connector health checks so brief outages never trigger any failover","Use one shared credential across all connectors to ease their administration","Deploy connectors near applications and users for resilience and low latency"], correct:3, explanation:"Connectors near apps/users improve resilience and latency. Single-region backhaul, disabled health checks, and shared creds are poor." },
  { id:61065, domain:5, level:3, question:"What is the role of mutual authentication between microservices?", options:["It lets a service skip checking the caller's identity to speed up requests","It compresses the data exchanged to reduce inter-service bandwidth use","It assigns a public IP to each service for direct external reachability","Each service verifies the other's identity before exchanging any data"], correct:3, explanation:"Mutual authentication has each service verify the other before data exchange. Skipping checks, compression, and public IPs are unrelated." },
  { id:61066, domain:5, level:1, question:"Which is the most effective way to operationalize conditional access at scale?", options:["Writing a unique manual rule for every individual user in the directory across all environments","Defining reusable, attribute-driven policies tested and deployed as code","Approving each access request by email before the user may proceed","Granting broad access and revoking it manually after incidents occur"], correct:1, explanation:"Reusable, attribute-driven policy-as-code scales conditional access. Per-user manual rules and email approvals do not scale." },
  { id:61067, domain:5, level:3, question:"What does the term trust but verify get replaced by in Zero Trust?", options:["Never trust and always verify every request regardless of its source","Verify once and then trust the session for its entire remaining duration","Trust internal sources fully and verify only requests from the internet","Verify devices but trust users implicitly after their first successful login"], correct:0, explanation:"ZT replaces trust-but-verify with never-trust-always-verify for every request. The other options reintroduce implicit trust." },
  { id:61068, domain:5, level:1, question:"Which is a recommended way to reduce standing access for developers?", options:["Grant permanent production access so debugging is never delayed by requests","Provide on-demand, time-boxed access with approval and full session logging","Share a single developer account so entitlements are simpler to administer","Disable logging on developer sessions to keep production telemetry lean"], correct:1, explanation:"On-demand, time-boxed, approved, logged access reduces standing access. Permanent access, shared accounts, and no logging are risky." },
  { id:61069, domain:5, level:3, question:"What does continuous diagnostics primarily provide to a Zero Trust program?", options:["A one-time security baseline captured during the initial deployment phase across all environments","A replacement for access policy by passively observing system behavior","Ongoing awareness of asset, configuration, and vulnerability state for action","A reduction in the telemetry collected from endpoints and network devices"], correct:2, explanation:"Continuous diagnostics gives ongoing asset/config/vuln awareness to drive action. It is not a one-time baseline or policy replacement." },
  { id:61070, domain:5, level:3, question:"Which is the best operational use of CASB in a Zero Trust SSE stack?", options:["Replacing the enterprise identity provider for all application authentication","Encrypting east-west traffic between workloads inside the private data center","Enforcing visibility, DLP, and policy for sanctioned and shadow cloud apps","Issuing the short-lived certificates used for workload mutual TLS sessions"], correct:2, explanation:"CASB provides visibility, DLP, and policy over cloud app usage. It is not an IdP, east-west encryptor, or workload CA." },
  { id:61071, domain:5, level:1, question:"What is a key reason to log privileged session activity centrally?", options:["To enable correlation, tamper-resistance, and review of high-impact actions","To reduce the storage burden on the individual administrator workstations","To allow administrators to delete their own session records when convenient","To improve the rendering speed of the administrator's remote desktop session"], correct:0, explanation:"Central logging enables correlation, tamper-resistance, and review of privileged actions. Local deletion and rendering are not the point." },
  { id:61072, domain:5, level:2, question:"Which is an appropriate response to a device that drops out of compliance mid-session?", options:["Allow the session to continue unchanged until the user logs out naturally","Permanently block the device from the network with no remediation path","Re-evaluate access and restrict or terminate the session based on policy","Increase the device's access so the user can fix the issue more easily"], correct:2, explanation:"Mid-session non-compliance should trigger re-evaluation and restriction/termination. Ignoring it or increasing access is wrong." },
  { id:61073, domain:5, level:1, question:"What does an access proxy contribute in a Zero Trust architecture?", options:["It permanently stores user credentials so logins can be skipped in future","It intercepts requests and enforces authentication and authorization per access","It compiles application code on demand as users request each page view","It assigns each backend server a routable public address for direct access across all environments"], correct:1, explanation:"An access proxy enforces authN/authZ per request in front of resources. It does not store creds, compile code, or assign public IPs." },
  { id:61074, domain:5, level:2, question:"Which is the most effective way to handle alert prioritization post-rollout?", options:["Treat every alert with equal urgency to ensure none are ever overlooked","Investigate alerts strictly in the order they happen to arrive in the queue across all environments","Suppress low-severity alerts permanently so the queue stays short and tidy","Score alerts by asset criticality, confidence, and risk to focus analyst effort"], correct:3, explanation:"Risk/criticality/confidence scoring focuses analyst effort effectively. Equal urgency, pure FIFO, and blanket suppression are weaker." },
  { id:61075, domain:5, level:2, question:"What does the automation pillar of Zero Trust maturity emphasize?", options:["Manually approving every access change to maintain tight human oversight across all environments","Orchestrating policy, response, and provisioning to act quickly and consistently","Disabling automated responses to avoid any accidental disruptive actions","Limiting automation strictly to scheduled overnight batch reporting jobs"], correct:1, explanation:"The automation pillar orchestrates policy/response/provisioning for speed and consistency. Manual-only or disabled automation is immature." },
  { id:61076, domain:5, level:2, question:"Which is a sound way to secure service-to-service calls in a microservices app?", options:["Allow any internal service to call any other since they share a trust zone","Use a single shared bearer token that every service presents on each call","Rely on the firewall to block calls, with no authentication between services","Require mTLS plus per-call authorization scoped to the calling identity"], correct:3, explanation:"mTLS plus identity-scoped per-call authorization secures service calls. Shared trust zones, shared tokens, and firewall-only are weak." },
  { id:61077, domain:5, level:1, question:"What is the purpose of mapping data flows before enforcing Zero Trust policy?", options:["To understand dependencies so enforcement does not break legitimate traffic","To increase network throughput by rerouting flows onto faster physical links","To permanently document flows for marketing the program to executive sponsors","To reduce the number of log sources the monitoring team must maintain"], correct:0, explanation:"Flow mapping reveals dependencies so enforcement avoids breaking legitimate traffic. It is not a throughput or marketing exercise." },
  { id:61078, domain:5, level:3, question:"Which is the best description of risk-adaptive policy enforcement?", options:["Policy outcomes are fixed and applied identically to every request received","Policy is enforced only on requests that originate from outside the network","Policy decisions are made by the requesting user rather than the policy engine","Policy outcomes change based on the computed risk of each individual request"], correct:3, explanation:"Risk-adaptive enforcement varies outcomes by per-request risk. Fixed, perimeter-only, or user-made decisions are not adaptive." },
  { id:61079, domain:5, level:3, question:"What does endpoint detection and response (EDR) contribute to Zero Trust?", options:["It issues workload certificates for mutual TLS between backend services across all environments","It replaces the identity provider as the source of user authentication","It supplies endpoint posture and threat signals and enables host containment","It encrypts data at rest on file servers across the entire enterprise"], correct:2, explanation:"EDR provides posture/threat signals and host containment, feeding ZT decisions. It is not a CA, IdP, or at-rest encryptor." },
  { id:61080, domain:5, level:2, question:"Which is an effective operational metric for device-pillar maturity?", options:["The average resale value of decommissioned hardware returned to vendors","The number of device models approved for purchase in the procurement catalog across all environments","The percentage of access from managed, compliant, and posture-checked devices","The total weight of all laptops issued to employees during the past year"], correct:2, explanation:"Share of access from managed, compliant, posture-checked devices gauges device maturity. Resale value and weight are irrelevant." },
  { id:61081, domain:5, level:3, question:"What is a primary purpose of integrating IAM with the policy engine?", options:["To let the policy engine store the only copy of all user passwords centrally","To supply authoritative identity and entitlement signals to access decisions","To replace network segmentation with identity as the sole control mechanism","To archive identity events without using them in any live access decision"], correct:1, explanation:"IAM supplies authoritative identity/entitlement signals to the engine. It does not store sole password copies or replace segmentation." },
  { id:61082, domain:5, level:3, question:"Which is a recommended practice when a privileged session shows anomalous commands?", options:["Allow the session to finish and review the recording during the next audit","Automatically grant additional privileges so the operator can resolve faster","Alert, optionally terminate, and require re-verification of the operator","Disable session recording to avoid capturing potentially sensitive commands"], correct:2, explanation:"Anomalous privileged commands warrant alerting, possible termination, and re-verification. Waiting, escalating, or disabling recording are wrong." },
  { id:61083, domain:5, level:3, question:"What does the term resource portal refer to in some Zero Trust deployments?", options:["A public marketing site describing the organization's security posture","A physical reception desk where visitors sign in before entering offices","A single sign-on page that authenticates users and brokers access to apps","A storage bucket holding archived logs for long-term legal-hold retention"], correct:2, explanation:"A resource portal authenticates users and brokers access to applications. It is not a marketing site, desk, or log archive." },
  { id:61084, domain:5, level:2, question:"Which is the best approach to securing CI/CD pipeline access to cloud accounts?", options:["Store long-lived cloud access keys in the pipeline's environment variables","Use short-lived federated credentials issued via workload identity federation","Share one administrator key across all pipelines to simplify the setup","Grant the pipeline standing admin in every account to avoid permission errors"], correct:1, explanation:"Short-lived federated credentials via workload identity federation are best. Long-lived keys, shared keys, and standing admin are insecure." },
  { id:61085, domain:5, level:2, question:"What is the purpose of continuous verification of context during a session?", options:["To verify context once at login and avoid re-checking it during the session","To detect changes such as new risk, location, or posture and react to them","To delegate context evaluation to the end user rather than the policy engine","To reduce the telemetry collected so sessions consume fewer log records"], correct:1, explanation:"Continuous context verification reacts to mid-session changes in risk/location/posture. One-time checks and user delegation are weaker." },
  { id:61086, domain:5, level:2, question:"Which is a sound way to handle secrets sprawl discovered during a ZT assessment?", options:["Leave the discovered secrets in place since rotating them risks outages","Copy them into a shared spreadsheet so teams can find them more easily","Centralize them in a vault, rotate exposed ones, and remove hardcoded copies","Lengthen the secrets so they are harder to guess but keep them where they are"], correct:2, explanation:"Centralizing in a vault, rotating exposed secrets, and removing hardcoded copies fixes sprawl. Leaving or copying them sustains risk." },
  { id:61087, domain:5, level:3, question:"What does an authorization scope define for an access token?", options:["The total number of times the token may be presented before it expires","The geographic region in which the token was originally issued to a client","The specific permissions and resources the token is allowed to access","The encryption algorithm used to protect the token's payload in transit"], correct:2, explanation:"A scope defines which permissions/resources the token may access, enforcing least privilege. Presentation count and region are not scope." },
  { id:61088, domain:5, level:3, question:"Which is an effective way to reduce the blast radius of a compromised credential?", options:["Grant the credential broad access so fewer separate credentials are needed","Extend the credential's validity so re-issuance does not interrupt service","Reuse the credential across systems so revocation is centrally simpler","Apply least privilege and segmentation so the credential reaches little"], correct:3, explanation:"Least privilege plus segmentation limits what a stolen credential reaches. Broad access, long validity, and reuse enlarge the blast radius." },
  { id:61089, domain:5, level:2, question:"What is the purpose of policy testing in a policy-as-code workflow?", options:["To guarantee that policies are never changed once they enter production","To hide policy logic from reviewers so the rule set remains confidential","To eliminate the need for any monitoring once the policy is deployed live across all environments","To validate policy behavior before deployment and catch unintended effects"], correct:3, explanation:"Policy testing validates behavior pre-deployment, catching unintended effects. It does not freeze policy, hide logic, or remove monitoring." },
  { id:61090, domain:5, level:1, question:"Which is the best operational handling of a newly discovered unmanaged device?", options:["Grant it the same access as managed devices once a user authenticates","Restrict it to limited access and route it through onboarding or remediation","Block it permanently with no path to becoming managed or compliant later","Ignore it because unmanaged devices cannot reach internal resources anyway across all environments"], correct:1, explanation:"Unmanaged devices should get limited access and an onboarding/remediation path. Equal access, permanent blocking, and ignoring are wrong." },
  { id:61091, domain:5, level:1, question:"What does the term step-down (or de-escalation) of access describe?", options:["Returning a user's privileges to baseline after elevated access is no longer needed","Permanently elevating a user so they retain rights after a task completes across all environments","Sharing elevated rights among a team so any member can act at any time","Disabling logging once a privileged task has been successfully completed"], correct:0, explanation:"Step-down returns privileges to baseline after elevated access is done, supporting JIT. Permanent elevation and sharing contradict it." },
  { id:61092, domain:5, level:2, question:"Which is a recommended way to validate Zero Trust controls continuously?", options:["Run a single penetration test at launch and assume controls stay effective","Rely solely on vendor assurances that the deployed products work correctly","Disable monitoring after launch to reduce the operational telemetry volume","Use continuous control monitoring and periodic adversary-emulation testing"], correct:3, explanation:"Continuous control monitoring plus adversary emulation validates controls over time. One-time tests and vendor assurances are insufficient." },
  { id:61093, domain:5, level:1, question:"What is the purpose of an entitlement catalog in Zero Trust access management?", options:["To define grantable access in business terms for consistent, reviewable requests","To store the encryption keys used for protecting data at rest in databases","To record the physical locations of all servers in the corporate data centers across all environments","To advertise internal services to anonymous users on the public internet"], correct:0, explanation:"An entitlement catalog defines grantable access for consistent, reviewable requests. It is not a key store or asset map." },
  { id:61094, domain:5, level:3, question:"Which is an effective approach to securing east-west traffic in a service mesh?", options:["Permit all sidecar-to-sidecar traffic by default to ease service discovery","Disable the mesh's telemetry so it collects less data about service calls","Route all internal calls through one external load balancer for inspection","Enforce mTLS and per-service authorization policies between all sidecars"], correct:3, explanation:"Mesh mTLS plus per-service authorization secures east-west traffic. Default-permit, disabled telemetry, and external routing are weaker." },
  { id:61095, domain:5, level:2, question:"What does the term identity-first security express?", options:["Identity is the primary control plane for access in a Zero Trust model","Network location remains the primary basis for all access decisions made","Identity is verified only for external users connecting from the internet","Identity verification is delegated entirely to each individual application"], correct:0, explanation:"Identity-first security makes identity the primary control plane. Network-location primacy and external-only verification are pre-ZT." },
  { id:61096, domain:5, level:2, question:"Which is a sound way to reduce manual toil in Zero Trust operations?", options:["Require human approval for every routine low-risk access request received","Automate routine decisions and reserve human review for high-risk exceptions","Disable automated provisioning so every entitlement is granted by hand","Forward all decisions to a single administrator to centralize accountability"], correct:1, explanation:"Automating routine decisions and escalating only high-risk exceptions cuts toil. Manual-everything approaches do not scale." },
  { id:61097, domain:5, level:1, question:"What is the operational benefit of correlating posture with identity at access time?", options:["It lets the system ignore the device entirely once the user is known","It removes the requirement for the user to authenticate when on a known device","It replaces continuous monitoring with a single check at the session start","It ensures both who and what are trustworthy before granting access"], correct:3, explanation:"Correlating posture with identity verifies both who and what before access. Ignoring the device or skipping authentication is wrong." },
  { id:61098, domain:5, level:3, question:"Which is the best way to handle a surge of false positives after enabling a ZT control?", options:["Analyze the noise, refine policy and detections, and adjust thresholds iteratively","Disable the control until someone has time to investigate every alert later","Raise alert severity so analysts feel more urgency to clear the backlog faster across all environments","Auto-close all new alerts so the queue returns to a manageable size quickly"], correct:0, explanation:"Analyzing noise and iteratively refining policy/thresholds resolves false positives. Disabling, inflating severity, or auto-closing are poor." },
  { id:61099, domain:5, level:2, question:"What does the term zero standing privilege (ZSP) describe?", options:["Administrators hold permanent rights that are always available on demand","No persistent privileges exist; access is granted just-in-time and then revoked","Every user is given identical baseline privileges that never change at all across all environments","Privileges are stored in a shared vault for the whole team to draw upon"], correct:1, explanation:"ZSP means no persistent privileges; access is JIT and revoked after use. Permanent rights and shared vaults are the opposite." },
  { id:61100, domain:5, level:2, question:"Which is an effective way to integrate UEBA with conditional access?", options:["Feed UEBA risk scores into the policy engine to trigger step-up or blocking","Use UEBA only for monthly reports and keep it isolated from access decisions","Replace the policy engine with UEBA so it makes all access decisions alone","Let UEBA automatically delete accounts whenever any anomaly is observed"], correct:0, explanation:"Feeding UEBA risk into the policy engine enables adaptive step-up/blocking. Isolation, full replacement, and auto-deletion are wrong." }
];
if (typeof window !== 'undefined') window.QUESTIONS_CCZT_C5 = QUESTIONS_CCZT_C5;
